     1→import React, { FC, useState, useCallback, useEffect, useMemo } from 'react';
     2→import { BackDropBottom, Text, Button, Box, ChooseButton } from '@semparar/design-system-app';
     3→import { PropsModalizeRef } from '@semparar/design-system-app/src/@types/modelize';
     4→import { eventSelectContent } from '~/constants/functions';
     5→import { Dimensions } from 'react-native';
     6→import { FilterOption, TYPE_LABELS, TransactionType } from '../../../services/models';
     7→
     8→interface FilterGroup {
     9→  label: string;
    10→  options: FilterOption[];
    11→}
    12→
    13→interface FiltersBottomSheetProps {
    14→  modalizeRef: React.RefObject<PropsModalizeRef>;
    15→  filterGroups: FilterGroup[];
    16→  onApplyFilters: (filters: any) => void;
    17→  initialFilters?: any;
    18→}
    19→
    20→interface MemoizedFilterGroupProps {
    21→  group: FilterGroup;
    22→  groupIndex: number;
    23→  selectedIndex: number | undefined;
    24→  filterItems: Array<{ id: number; title: string }>;
    25→  onFilterChange: (groupIndex: number, options: FilterOption[]) => (item: any, index: number | number[]) => void;
    26→}
    27→
    28→const MemoizedFilterGroup = React.memo<MemoizedFilterGroupProps>(({ 
    29→  group, 
    30→  groupIndex, 
    31→  selectedIndex, 
    32→  filterItems,
    33→  onFilterChange 
    34→}) => {
    35→  const filterChangeHandler = onFilterChange(groupIndex, group.options);
    36→  
    37→  return (
    38→    <Box>
    39→      <Text 
    40→        type="paragraphXL" 
    41→        color="INTENSE_COLOR_05" 
    42→        mt={groupIndex === 0 ? "xxxs" : "xxs"} 
    43→        ml="small" 
    44→        mb="xxxs"
    45→      >
    46→        {group.label}
    47→      </Text>
    48→
    49→      <ChooseButton
    50→        items={filterItems}
    51→        type="select"
    52→        ml="small"
    53→        numColumns={3}
    54→        selectMultipleItems={false}
    55→        defaultOption={selectedIndex}
    56→        onPress={filterChangeHandler}
    57→      />
    58→    </Box>
    59→  );
    60→});
    61→
    62→const FiltersBottomSheet: FC<FiltersBottomSheetProps> = ({
    63→  modalizeRef,
    64→  filterGroups,
    65→  onApplyFilters,
    66→  initialFilters = {},
    67→}) => {
    68→  const [selectedFilters, setSelectedFilters] = useState<Record<number, any>>(initialFilters);
    69→  
    70→  const screenWidth = useMemo(() => Dimensions.get('window').width, []);
    71→
    72→  useEffect(() => {
    73→    setSelectedFilters(initialFilters);
    74→  }, [initialFilters]);
    75→
    76→  const filterItemsMap = useMemo(() => {
    77→    return filterGroups.map(group => 
    78→      group.options.map((option, idx) => ({
    79→        id: idx,
    80→        title: option.label,
    81→      }))
    82→    );
    83→  }, [filterGroups]);
    84→
    85→  const selectedIndices = useMemo(() => {
    86→    return filterGroups.map((group, groupIndex) => {
    87→      const selectedValue = selectedFilters[groupIndex];
    88→      
    89→      if (selectedValue === undefined) {
    90→        return undefined;
    91→      }
    92→      
    93→      const index = group.options.findIndex(opt => opt.value === selectedValue);
    94→      return index >= 0 ? index : undefined;
    95→    });
    96→  }, [filterGroups, selectedFilters]);
    97→
    98→  const handleFilterChange = useCallback((groupIndex: number, options: FilterOption[]) => {
    99→    return (item: any, index: number | number[]) => {
   100→      const selectedIndex = Array.isArray(index) ? index[0] : index;
   101→      if (selectedIndex !== undefined && selectedIndex >= 0) {
   102→        const value = options[selectedIndex].value;
   103→
   104→        setSelectedFilters(prev => {
   105→          const currentValue = prev[groupIndex];
   106→          const newValue = currentValue === value ? undefined : value;
   107→          return { ...prev, [groupIndex]: newValue };
   108→        });
   109→      }
   110→    };
   111→  }, []);
   112→
   113→  const handleClear = useCallback(() => {
   114→    modalizeRef.current?.close?.();
   115→    
   116→    setTimeout(() => {
   117→      setSelectedFilters({});
   118→      onApplyFilters({});
   119→    }, 100);
   120→  }, [onApplyFilters, modalizeRef]);
   121→
   122→  const handleApply = useCallback(() => {
   123→    const filtersToApply = selectedFilters;
   124→    const period = filtersToApply[0];
   125→    const type = filtersToApply[1];
   126→    
   127→    const contentIdParts = ['filtrar'];
   128→    if (period) contentIdParts.push(String(period));
   129→    if (type) {
   130→      const typeLabel = TYPE_LABELS[type as TransactionType] || type;
   131→      contentIdParts.push(typeLabel.toLowerCase());
   132→    }
   133→    
   134→    const contentId = contentIdParts.join('_').toLowerCase();
   135→
   136→    eventSelectContent({
   137→      content_type: 'cta',
   138→      content_id: contentId,
   139→      location_1: 'monetizacao',
   140→      location_2: 'hub_recompensas_spmais',
   141→      location_3: 'filtro_extrato_hub'
   142→    });
   143→    
   144→    modalizeRef.current?.close?.();
   145→    
   146→    setTimeout(() => {
   147→      onApplyFilters(filtersToApply);
   148→    }, 100);
   149→  }, [selectedFilters, onApplyFilters, modalizeRef]);
   150→
   151→  return (
   152→    <BackDropBottom modalizeRef={modalizeRef} pd="none">
   153→      <Box mt="xxs">
   154→        <Box>
   155→          {filterGroups.map((group, groupIndex) => (
   156→            <MemoizedFilterGroup
   157→              key={groupIndex}
   158→              group={group}
   159→              groupIndex={groupIndex}
   160→              selectedIndex={selectedIndices[groupIndex]}
   161→              filterItems={filterItemsMap[groupIndex]}
   162→              onFilterChange={handleFilterChange}
   163→            />
   164→          ))}
   165→        </Box>
   166→
   167→        <Box mt="small" direction width={screenWidth} ml="small">
   168→            <Button
   169→              text="Limpar"
   170→              width={screenWidth * 0.43}
   171→              type="secundaryMedium"
   172→              onPress={handleClear}
   173→            
   174→            />
   175→            <Button
   176→              width={screenWidth * 0.43}
   177→              text="Filtrar"
   178→              type="primaryMedium"
   179→              ml="xs"
   180→              onPress={handleApply}
   181→            />
   182→        </Box>
   183→      </Box>
   184→    </BackDropBottom>
   185→  );
   186→};
   187→
   188→export default FiltersBottomSheet;
   189→
